        for (int j = 0; j < k; j++) sumw += spec->leaf_weight[c][j];
        if (sumw <= 0) sumw = 1;
        st->coarse_start[c] = leaves.n;
        st->coarse_len[c] = k;
        double vj[MAX_LEAVES];
        double vtot = 0.0;
        double jw = 0.0;
        for (int j = 0; j < k; j++) {
            vj[j] = coarse.cells[c].vol * (double)spec->leaf_weight[c][j] / (double)sumw;
            vtot += vj[j];
            jw += vj[j] * (double)j;
        }
        double jbar = (vtot > 0.0) ? jw / vtot : 0.0;
        for (int j = 0; j < k; j++) {
            int gi = leaves.n++;
            leaves.cells[gi].idx = gi;
            leaves.cells[gi].vol = vj[j];
            double s = (k > 1) ? (1.0 + LEAF_SPREAD * ((double)j - jbar)) : 1.0;
            // Normalize the shape so the volume-weighted totals are conserved:
            // sum_j (q_child * vol_child) == q_parent * vol_parent
