                denom += vj[jj] * ss;
            }
            if (denom <= 0.0) denom = coarse.cells[c].vol;
            double scale = coarse.cells[c].vol * s / denom;
            for (int v = 0; v < NVAR; v++) {
                leaves.cells[gi].q[v] = coarse.cells[c].q[v] * scale;
            }
            leaves.cells[gi].tier = (k > 1) ? 1 : 0;
            leaves.cells[gi].parent = (k > 1) ? c : -1;
        }
    }
    st->grid = leaves;

    int changed[MAX_CELLS];
    int nch = 0;
    for (int i = 0; i < leaves.n; i++) changed[nch++] = i;
